+    #[test]
+    fn proof_unsafe_set_completeness() {
+        let v = solve_hji();
+        for s in 0..STATES {
+            let (r, _, a) = decode(s);
+            if is_unsafe(r, a) {
+                assert_eq!(
+                    v[s], UNSAFE_PENALTY,
+                    "Unsafe state {s} not at penalty: V={}",
